    function keepKerryShelleyClose() {
        if (kerryShelley && rider) {
            partWayThereX = 0.02 * (rider.x - 12 - kerryShelley.x)
            partWayThereY = 0.02 * (rider.y - 8 - kerryShelley.y)
            if (kerryShelley.x >= 80) {
                kerryShelley.x = 80
            }
            if (kerryShelley.y >= rider.y - 8) {
                kerryShelley.y = rider.y - 8
            }
            kerryShelley.setPosition(partWayThereX + kerryShelley.x, partWayThereY + kerryShelley.y)
            kerryShelley.z = kerryShelley.bottom
        }
    }
