    function slowTracks() {
        if (experienceLevel == 1) {
            animation.runImageAnimation(
                rider,
                riderImages,
                slowingTrackPeriod,
                true
            )
        } else if (experienceLevel == 2) {
            animation.runImageAnimation(
                rider,
                intermediateRiderImages,
                slowingTrackPeriod,
                true
            )
        } else {
            animation.runImageAnimation(
                rider,
                expertRiderImages,
                slowingTrackPeriod,
                true
            )
        }
        if (atDestination) {
            controller.moveSprite(rider, 15, 5)
        }
        if (duke) {
            animation.runImageAnimation(
                duke,
                dukeImages,
                slowingTrackPeriod,
                true
            )
        }
        if (kerryShelley) {
            animation.runImageAnimation(
                kerryShelley,
                kerryShelleyImages,
                slowingTrackPeriod,
                true
            )
        }
        if (grood) {
            animation.runImageAnimation(
                grood,
                groodImages,
                slowingTrackPeriod,
                true
            )
        }
    }
